from sympy import prime, primefactors, nextprime
SEARCH_GOAL = 120 # Find this many terms
def is_prime_complete(n):
    pf = primefactors(n)
    return prime(len(pf)) == pf[-1]
last_prime_complete, results = 2, []
while len(results) < SEARCH_GOAL:
    results.append(nextprime(last_prime_complete))
    last_prime_complete += 2
    while not is_prime_complete(last_prime_complete): last_prime_complete += 2
print(results)

